func testAccIAM3FolderAccessPolicy_accessPolicyFolderMinimalExample(context map[string]interface{}) string {
	return acctest.Nprintf(`
resource "google_folder" "folder" {
  provider     = google-beta
  display_name = "%{folder_name}"
  parent       = "organizations/%{org_id}"
  deletion_protection = false
}
resource "google_project" "project" {
  provider        = google-beta
  project_id      = "%{project_name}"
  name            = "%{project_name}"
  folder_id       = google_folder.folder.folder_id
  billing_account = "%{billing_account}"
  deletion_policy = "DELETE"
  depends_on = [google_folder.folder]
}
resource "google_project_service" "iam_api" {
  provider = google-beta
  project  = google_project.project.project_id
  service  = "iam.googleapis.com"
  disable_on_destroy = false
  depends_on = [google_project.project]
}
resource "time_sleep" "wait_for_propagation" {
  create_duration = "30s"
  depends_on = [
    google_folder.folder,
    google_project_service.iam_api,
  ]
}
resource "google_service_account" "test_sa" {
  provider        = google-beta
  account_id   = "%{account_id}"
  display_name = "Test Service Account for Access Policy"
  project      = google_project.project.project_id
  depends_on = [
      time_sleep.wait_for_propagation
  ]
}
resource "google_iam_folder_access_policy" "example" {
  provider          = google-beta
  folder            = google_folder.folder.folder_id
  location          = "global"
  access_policy_id  = "%{access_policy_id}"
  details {
    rules {
      effect      = "ALLOW"
      principals  = ["principal://iam.googleapis.com/projects/-/serviceAccounts/${google_service_account.test_sa.email}"]
      operation {
        permissions = ["eventarc.googleapis.com/messageBuses.publish"]
      }
    }
  }
  depends_on = [
    time_sleep.wait_for_propagation,
    google_service_account.test_sa
  ]
}
`, context)
}

func testAccIAM3FolderAccessPolicy_accessPolicyFolderFullExample(context map[string]interface{}) string {
	return acctest.Nprintf(`
resource "google_folder" "folder" {
  provider     = google-beta
  display_name = "%{folder_name}"
  parent       = "organizations/%{org_id}"
  deletion_protection = false
}
resource "google_project" "project" {
  provider        = google-beta
  project_id      = "%{project_name}"
  name            = "%{project_name}"
  folder_id       = google_folder.folder.folder_id
  billing_account = "%{billing_account}"
  deletion_policy = "DELETE"
  depends_on = [google_folder.folder]
}
resource "google_project_service" "iam_api" {
  provider = google-beta
  project  = google_project.project.project_id
  service  = "iam.googleapis.com"
  disable_on_destroy = false
  depends_on = [google_project.project]
}
resource "time_sleep" "wait_for_propagation" {
  create_duration = "30s"
  depends_on = [
    google_folder.folder,
    google_project_service.iam_api,
  ]
}
resource "google_service_account" "test_sa" {
  provider        = google-beta
  account_id   = "%{account_id}"
  display_name = "Test Service Account for Access Policy"
  project      = google_project.project.project_id
  depends_on = [
      time_sleep.wait_for_propagation
  ]
}
resource "google_service_account" "excluded_sa" {
  provider        = google-beta
  account_id   = "%{excluded_account_id}"
  display_name = "Excluded Service Account for Access Policy"
  project      = google_project.project.project_id
  depends_on = [
      time_sleep.wait_for_propagation
  ]
}
resource "google_iam_folder_access_policy" "example" {
  provider          = google-beta
  folder            = google_folder.folder.folder_id
  location          = "global"
  access_policy_id  = "%{access_policy_id}"
  display_name      = "%{display_name}"
  annotations    = {"foo": "bar"}
  details {
    rules {
      description = "%{allow_rule_description}"
      effect      = "ALLOW"
      principals  = ["principal://iam.googleapis.com/projects/-/serviceAccounts/${google_service_account.test_sa.email}"]
      excluded_principals = ["principal://iam.googleapis.com/projects/-/serviceAccounts/${google_service_account.excluded_sa.email}"]
      operation {
        permissions = ["eventarc.googleapis.com/messageBuses.publish"]
      }
      conditions {
        service = "iam.googleapis.com"
        expression   = "resource.matchTag('%{org_id}/env', 'test')"
      }
    }
    rules {
      description = "%{deny_rule_description}"
      effect      = "DENY"
      principals  = ["principalSet://goog/public:all"]
      excluded_principals = ["principal://iam.googleapis.com/projects/-/serviceAccounts/${google_service_account.excluded_sa.email}"]
      operation {
        permissions = ["eventarc.googleapis.com/messageBuses.publish"]
      }
      conditions {
        service = "iam.googleapis.com"
        expression   = "!resource.matchTag('%{org_id}/env', 'test')"
      }
    }
  }
  depends_on = [
    time_sleep.wait_for_propagation,
    google_service_account.test_sa,
    google_service_account.excluded_sa
  ]
}
`, context)
}

func testAccCheckIAM3FolderAccessPolicyDestroyProducer(t *testing.T) func(s *terraform.State) error {
	return func(s *terraform.State) error {
		for name, rs := range s.RootModule().Resources {
			if rs.Type != "google_iam_folder_access_policy" {
				continue
			}
			if strings.HasPrefix(name, "data.") {
				continue
			}

			config := acctest.GoogleProviderConfig(t)
			url, err := tpgresource.ReplaceVarsForTest(config, rs, transport_tpg.BaseUrl(iam3.Product, config)+"folders/{{folder}}/locations/{{location}}/accessPolicies/{{access_policy_id}}")
			if err != nil {
				return err
			}

			billingProject := ""

			if config.BillingProject != "" {
				billingProject = config.BillingProject
			}

			_, err = transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
				Config:    config,
				Method:    "GET",
				Project:   billingProject,
				RawURL:    url,
				UserAgent: config.UserAgent,
			})
			if err == nil {
				return fmt.Errorf("IAM3FolderAccessPolicy still exists at %s", url)
			}
		}

		return nil
	}
}
